'use strict';

var _index = require('./index');

describe('packets', function () {
  describe('suback', function () {
    describe('decode', function () {
      test('it works', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        0x90, // packetType + flags
        3, // remainingLength
        // variableHeader
        0, // id MSB
        1, // id LSB
        // payload
        0]))).toEqual({
          type: 'suback',
          id: 1,
          returnCodes: [0]
        });
      });
    });
  });
});

